const item = $input.first().json;
const ctx = $('Normalize Input').first().json;

let ai = {};
try {
  const raw = item.choices?.[0]?.message?.content || '{}';
  ai = JSON.parse(raw);
} catch (e) {
  ai = {
    lead_score: 5,
    icp_match: 'Medium',
    is_hot: false,
    pitch_subject: 'Automation idea for ' + ctx.company,
    pitch_email: '<p>Hi ' + ctx.lead_name + ',</p><p>I help companies like ' + ctx.company + ' eliminate manual work with custom n8n automations. I noticed ' + ctx.pain_point + ' — that is exactly the problem I solve every day.</p><p>I have built similar systems that save clients 10+ hours per week. Can we jump on a 20-minute call this week?</p><p>Best,<br>Azmain</p>',
    day3_subject: 'Following up — ' + ctx.company + ' automation',
    day3_email: '<p>Hi ' + ctx.lead_name + ',</p><p>Just circling back. I recently automated a similar workflow for a client in your industry — they cut manual work by 80% in week one. Worth a quick chat?</p><p>Best, Azmain</p>',
    day7_subject: 'Last note from Azmain — ' + ctx.company,
    day7_email: '<p>Hi ' + ctx.lead_name + ',</p><p>I will keep this short — if automating your ops is not a priority right now, totally understood. Feel free to reach out whenever the timing is right. Wishing ' + ctx.company + ' all the best.</p><p>— Azmain</p>',
    qualification_notes: 'Parse error on AI response — manual review required.',
    recommended_service: ctx.service_interest,
    estimated_deal_value: '$500–$2,000'
  };
}

return [{ json: { ...ctx, ...ai } }];

